import sqlite3
import threading
from contextlib import contextmanager
from typing import Optional

class FileAccessControlSystem:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self.file_locks = {}
        self.locks_lock = threading.Lock()
        self._init_db()
    
    def _init_db(self):
        """Initialize the database with necessary tables."""
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS user_permissions (
                user_id TEXT,
                file_path TEXT,
                access_level TEXT,
                PRIMARY KEY (user_id, file_path)
            )
        ''')
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS file_access_log (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id TEXT,
                file_path TEXT,
                access_granted INTEGER,
                timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
            )
        ''')
        conn.commit()
        conn.close()
    
    def _get_file_lock(self, file_path: str) -> threading.Lock:
        """Get or create a lock for a specific file."""
        with self.locks_lock:
            if file_path not in self.file_locks:
                self.file_locks[file_path] = threading.Lock()
            return self.file_locks[file_path]
    
    @contextmanager
    def _get_db_connection(self):
        """Context manager for database connections."""
        conn = sqlite3.connect(self.db_path, timeout=10.0)
        conn.isolation_level = 'IMMEDIATE'
        try:
            yield conn
            conn.commit()
        except Exception:
            conn.rollback()
            raise
        finally:
            conn.close()
    
    def grant_permission(self, user_id: str, file_path: str, access_level: str):
        """Grant permission to a user for a file."""
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute('''
                INSERT OR REPLACE INTO user_permissions (user_id, file_path, access_level)
                VALUES (?, ?, ?)
            ''', (user_id, file_path, access_level))
    
    def revoke_permission(self, user_id: str, file_path: str):
        """Revoke permission from a user for a file."""
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute('''
                DELETE FROM user_permissions
                WHERE user_id = ? AND file_path = ?
            ''', (user_id, file_path))
    
    def read_file_with_permission(self, user_id: str, file_path: str) -> Optional[str]:
        """
        Atomically check permission and read file with proper locking.
        This prevents TOCTOU (Time-of-check to time-of-use) race conditions.
        """
        file_lock = self._get_file_lock(file_path)
        
        with file_lock:
            with self._get_db_connection() as conn:
                cursor = conn.cursor()
                
                # Begin transaction and check permission atomically
                cursor.execute('BEGIN IMMEDIATE')
                
                cursor.execute('''
                    SELECT access_level FROM user_permissions
                    WHERE user_id = ? AND file_path = ?
                ''', (user_id, file_path))
                
                result = cursor.fetchone()
                
                if result and result[0] == 'read':
                    # Permission granted - log the access
                    cursor.execute('''
                        INSERT INTO file_access_log (user_id, file_path, access_granted)
                        VALUES (?, ?, 1)
                    ''', (user_id, file_path))
                    
                    try:
                        # Read file while holding both database transaction and file lock
                        with open(file_path, 'r') as f:
                            content = f.read()
                        
                        conn.commit()
                        return content
                    except FileNotFoundError:
                        conn.rollback()
                        return None
                    except Exception:
                        conn.rollback()
                        raise
                else:
                    # Permission denied - log the denied access
                    cursor.execute('''
                        INSERT INTO file_access_log (user_id, file_path, access_granted)
                        VALUES (?, ?, 0)
                    ''', (user_id, file_path))
                    conn.commit()
                    return None
    
    def read_file_with_permission_v2(self, user_id: str, file_path: str) -> Optional[str]:
        """
        Alternative implementation using SELECT FOR UPDATE pattern.
        This ensures the permission check is locked during the entire operation.
        """
        file_lock = self._get_file_lock(file_path)
        
        with file_lock:
            with self._get_db_connection() as conn:
                cursor = conn.cursor()
                
                # Use a transaction with row-level locking
                cursor.execute('BEGIN IMMEDIATE')
                
                # Lock the permission row for this operation
                cursor.execute('''
                    SELECT access_level FROM user_permissions
                    WHERE user_id = ? AND file_path = ?
                ''', (user_id, file_path))
                
                result = cursor.fetchone()
                access_granted = result and result[0] == 'read'
                
                # Log the access attempt
                cursor.execute('''
                    INSERT INTO file_access_log (user_id, file_path, access_granted)
                    VALUES (?, ?, ?)
                ''', (user_id, file_path, 1 if access_granted else 0))
                
                if access_granted:
                    try:
                        with open(file_path, 'r') as f:
                            content = f.read()
                        conn.commit()
                        return content
                    except FileNotFoundError:
                        conn.rollback()
                        return None
                    except Exception:
                        conn.rollback()
                        raise
                else:
                    conn.commit()
                    return None


